SELECT issue_reason, COUNT(*) AS total_count
FROM issuance_history
GROUP BY issue_reason;

SELECT 
  (SELECT COUNT(DISTINCT ssn_id) FROM ssns) AS total_ssn_issued,
  (SELECT COUNT(DISTINCT ssn_id) FROM validation_logs) AS total_ssn_validated;

SELECT COUNT(DISTINCT ssn_number) 
FROM ssns 
WHERE valid_ssn = 'Valid';

SELECT COUNT(DISTINCT ssn_id) AS issuance_count
FROM ssns
WHERE cardholder_id = 1;

SELECT COUNT(*) 
FROM fraud_reports 
WHERE status = 'under investigation';
